generators.postProcess:
function (n) {
    try {
      return n.split("\n").filter(e => e.trim() && e !== "Available Generators:").map(e => ({
        name: e.trim(),
        icon: "https://avatars.githubusercontent.com/u/1714870?v=4",
        displayName: o(e),
        description: "".concat(o(e), " Generator"),
        priority: 100,
        options: [{
          name: "--help",
          description: "Help of \"".concat(o(e), "\" generator")
        }]
      }));
    } catch (e) {
      return console.error(e), [];
    }
  }
